{"name": "Scenario1","cron": "","period": -1,"code": "alarm_triggered := false
if (((#DoorLock).doorControl_door == 'open') and ((#Alarm).alarm_alarm == 'off')) {
    if (alarm_triggered == false) {
        (#Alarm).alarm_siren()
        if ((#Blind).blind_blind == 'open') {
            (#Blind).blind_close()
        }
        alarm_triggered = true
    }
} else {
    alarm_triggered = false
}
aircon_triggered := false
if (((#AirConditioner).switch_switch == 'off') and ((#TemperatureSensor).temperatureMeasurement_temperature >= 30)) {
    if (aircon_triggered == false) {
        (#AirConditioner).airConditionerMode_setAirConditionerMode('cool')
        (#AirConditioner).switch_on()
        aircon_triggered = true
    }
} else {
    aircon_triggered = false
}"}

