[{'name': 'Scenario1', 'cron': '', 'period': 100, 'code': 'runningStartTime_ms := 0
waitingFanOn := false
if ((#Irrigator).switch_switch == "on") {
  if (runningStartTime_ms == 0) {
    runningStartTime_ms = (#Clock).clock_timestamp
  }
  waitingFanOn = false
} else {
  if ((runningStartTime_ms != 0) and (waitingFanOn == false)) {
    elapsed = (#Clock).clock_timestamp - runningStartTime_ms
    if (elapsed >= 10000) {
      (#Fan).switch_on()
      waitingFanOn = true
      runningStartTime_ms = 0
    }
  } else if (waitingFanOn == true) {
    runningStartTime_ms = 0
  }
}'}]

