[{'name': 'SoilMoistureLowConsecutiveCheck', 'cron': '', 'period': 1000, 'code': 'count := 0
lowest := 101.0
secondIsLowest := false
if (#Clock).clock_month == 3 {
  count = 0
  lowest = 101.0
  secondIsLowest = false
  break
}
soil = (#SoilMoistureSensor).soilHumidityMeasurement_soilHumidity
if (soil <= 15.0) {
  count = count + 1
  if (count == 2) {
    lowest = soil
    secondIsLowest = true
  } else if (count == 3) {
    secondIsLowest = (lowest < soil)
  } else if (count > 3) {
    count = 1
    lowest = 101.0
    secondIsLowest = false
  }
} else {
  count = 0
  lowest = 101.0
  secondIsLowest = false
}
if ((count >= 3) and (secondIsLowest == true)) {
  (#Irrigator).switch_on()
  all(#Blind).blind_close()
  count = 0
  lowest = 101.0
  secondIsLowest = false
  break
}'}]

