step := 0
timer := 0
if (triggered == false) {
  wait until(any(#Light).switch_switch == "off")
  triggered = true
  step = 1
  timer = 0
}
if (triggered == true) {
  timer = timer + period
  if (step == 1 and timer >= 3000) {
    all(#Pump).switch_off()
    step = 2
    timer = 0
  }
  if (step == 2 and timer >= 5000) {
    all(#Blind).blind_close()
    step = 3
    timer = 0
  }
  if (step == 3 and timer >= 7000) {
    all(#Light).switch_on()
    step = 4
    timer = 0
  }
  if (step == 4) {
    if (any(#Alarm).alarm_alarmVolume != "mute") {
      all(#Alarm).alarm_siren()
    } else {
      all(#Alarm).alarm_siren()
    }
