{"name": "Scenario1","cron": "0 9 * * 1-5","period": 0,"code": "triggered1 := false
if ((#Window).windowControl_window == 'closed' and (#AirQualityDetector).carbonDioxideMeasurement_carbonDioxide >= 1000 and (#AirQualityDetector).temperatureMeasurement_temperature >= 30) {
    if (triggered1 == false) {
        (#Clock).clock_delay(5000)
