    }
}
if (triggered1 == true and triggered2 == false) {
    if ((#AirQualityDetector).dustSensor_fineDustLevel >= 50) {
        dust_high_count = dust_high_count + 1
    } else {
        dust_high_count = 0
    }
    if (dust_high_count >= 60) {
        (#Window).windowControl_close()
        (#Fan).switch_off()
        if ((#HumiditySensor).relativeHumidityMeasurement_humidity <= 40) {
            (#Humidifier).switch_on()
        }
        if ((#SoilMoistureSensor).soilHumidityMeasurement_soilHumidity <= 25 and (#Irrigator).switch_switch == 'off') {
