}"}

column10:
[{'name': 'MorningVentilationAndAirQualityControl', 'cron': '0 9 * * 1-5', 'period': 1000, 'code': 'ventilationStarted := false
pmOverThresholdStart := 0
fanWasTurnedOn := false
waitAfterOpenDone := false
weekdays := ["monday", "tuesday", "wednesday", "thursday", "friday"]
if ((#Clock).clock_weekday == "saturday" or (#Clock).clock_weekday == "sunday") {
  break
}
if (ventilationStarted == false) {
  if (((all(#Window).windowControl_window == "closed") and
       ((#AirQualityDetector).carbonDioxideMeasurement_carbonDioxide > 1000.0) and
       ((#AirQualityDetector).temperatureMeasurement_temperature > 30.0))) {
    waitAfterOpenDone = false
    ventilationStarted = true
    pmOverThresholdStart = 0
    fanWasTurnedOn = false
    wait until(waitAfterOpenDone == true)
  } else {
    break
  }
}
if (ventilationStarted == true and waitAfterOpenDone == false) {
  (#Window).windowControl_open()
  (#Clock).clock_delay(5000)
  if (any(#Fan).switch_switch == "off") {
    all(#Fan).switch_on()
    fanWasTurnedOn = true
  }
  waitAfterOpenDone = true
}
pmLevel = (#AirQualityDetector).dustSensor_dustLevel
currentTime = (#Clock).clock_timestamp
if ((pmLevel > 50) == true) {
  if (pmOverThresholdStart == 0) {
    pmOverThresholdStart = currentTime
  } else {
    elapsed = currentTime - pmOverThresholdStart
    if (elapsed >= 60000) {
      all(#Window).windowControl_close()
      if (fanWasTurnedOn == true) {
        all(#Fan).switch_off()
      }
      hum = (#HumiditySensor).relativeHumidityMeasurement_humidity
      soilHum = (#SoilMoistureSensor).soilHumidityMeasurement_soilHumidity
      irrigatorState = (#Irrigator).switch_switch
      if (hum < 40.0) {
        all(#Humidifier).switch_on()
      }
      if ((soilHum < 25.0) and (irrigatorState == "off")) {
        all(#Irrigator).switch_on()
      }
      break
    }
  }
} else {
  pmOverThresholdStart = 0
}'}]

