{"name": "Scenario1", "cron": "0 22 * * *", "period": 100, "code": "sirenTriggered := false
openCount := 0
openDuration := 0

if ((#Window #Bottom).windowControl_window == "open" and (#Light #Even).switch_switch == "on") {
  (#Siren).sirenMode_setSirenMode("siren")
  sirenTriggered = true
}


if (sirenTriggered == true) {
  (#Clock).clock_delay(5000)
  (#Blind).blind_close()
  sirenTriggered = false
} 


if ((#Door #Odd).doorControl_door == "open") {
  wait until ((#Door #Odd).doorControl_door == "closed")
  openCount = openCount + 1


if (openCount == 2) {
    (#Curtain).curtain_close()
    openDuration = openDuration + 5000
    (#Alarm).alarm_strobe()
    (#Clock).clock_delay(openDuration)
    (#Alarm).alarm_off()
    openCount = 0
    openDuration = 0
  }
}

