[{'name': 'DoorOpenCloseCamera', 'cron': '', 'period': 100, 'code': 'state := "unknown"
timer := 0
lastDoorState := "unknown"
doorState = (#DoorLock).doorControl_door
if ((doorState == "closing") or (doorState == "open") or (doorState == "opening") or (doorState == "closed")) {
  if (doorState != lastDoorState) {
    state = doorState
    timer = 0
    (#Camera).camera_take()
  } else {
    timer = timer + period
    if (timer >= 5000) {
      timer = 0
      (#Camera).camera_take()
    }
  }
  lastDoorState = doorState
} else {
  state = "unknown"
  lastDoorState = doorState
  timer = 0
}'}]

