notificationPlayed := false
if (any(#Light).switch_switch == "on") {
  if (lightOnStartTime == 0) {
    lightOnStartTime = (#Clock).clock_timestamp
    notificationPlayed = false
  }
  elapsed := (#Clock).clock_timestamp - lightOnStartTime
  if ((elapsed >= 1800000) and (notificationPlayed == false)) {
    if (any(#Alarm)) {
      all(#Alarm).alarm_siren()
    } else if (any(#Siren)) {
      all(#Siren).sirenMode_setSirenMode('siren')
    }
    notificationPlayed = true
  }
} else {
  lightOnStartTime = 0
  notificationPlayed = false
}'}]

